6. Environment Variables Type Safety

// lib/env.ts
const requiredEnvVars = [
'MONGODB_URI',
'JWT_SECRET',
'NEXTAUTH_SECRET',
] as const;
type EnvVar = typeof requiredEnvVars[number];
function getEnv(key: EnvVar): string {
const value = process.env[key];
if (!value) {
throw new Error(`Missing required environment variable: ${key}`);
}
return value;
}
export const env = {
mongodbUri: getEnv('MONGODB_URI'),
jwtSecret: getEnv('JWT_SECRET'),
nextAuthSecret: getEnv('NEXTAUTH_SECRET'),
};

Enter fullscreen mode

Exit fullscreen mode

Now instead of process.env.MONGODB_URI! everywhere — import from env and get type safety plus runtime validation.

7. Generic Fetch Hook

// hooks/useFetch.ts
import { useState, useEffect } from 'react';
interface FetchState<T> {
data: T | null;
loading: boolean;
error: string | null;
}
export function useFetch<T>(url: string): FetchState<T> {
const [state, setState] = useState<FetchState<T>>({
data: null,
loading: true,
error: null,
});
useEffect(() => {
let cancelled = false;
async function fetchData() {
try {
const res = await fetch(url);
if (!res.ok) throw new Error(`HTTP ${res.status}`);
const data: T = await res.json();
if (!cancelled) setState({ data, loading: false, error: null });
} catch (err) {
if (!cancelled) {
setState({ data: null, loading: false, error: String(err) });
}
}
}
fetchData();
return () => { cancelled = true; };
}, [url]);
return state;
}

Enter fullscreen mode

Exit fullscreen mode

Usage:

const { data, loading, error } = useFetch<User[]>('/api/users');

Enter fullscreen mode

Exit fullscreen mode

The cancelled flag prevents state updates on unmounted components — a common memory leak.

Summary

Pattern
Why

Type API responses
No more any — catch errors at compile time

Explicit component props
Self-documenting, refactor-safe components

Typed Server Actions
Know exactly what your actions return

Page prop types
Next.js 15 requires awaiting params

Utility types
Reuse types without duplication

Typed env vars
Crash at startup not at runtime

Generic hooks
Reusable data fetching with full type safety

TypeScript feels slow at first. After a month you'll never go back.

